{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are set by federal poverty guidelines (not specified in current sources for 2026; check current HHS poverty guidelines for precise figures). Priority given to veterans/qualified spouses, individuals over 65, those with disabilities, low literacy, limited English proficiency, rural residents, homeless/at risk, low employment prospects, or prior American Job Center users.[2][5][7]",
    "asset_limits": null,
    "other_requirements": ["Unemployed", "Poor employment prospects", "Low-income (≤125% FPL)", "U.S. citizen or eligible resident (inferred from federal program)"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time paid community service work (average 20 hours/week at highest of federal/state/local minimum wage); on-the-job training in nonprofits/public facilities (e.g., schools, hospitals, senior centers); skill development (e.g., computer/digital literacy, vocational skills); job placement assistance to unsubsidized employment; supportive services (e.g., dental, vision, clothing, transportation).[2][3][4][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: 316-771-6750 (Kansas SCSEP team)", "Contact SER Jobs For Progress (provider in Kansas via Kansas WorkforceONE)", "Contact AARP Foundation SCSEP or local grantees for intake", "American Job Centers for employment assistance"],
    "processing_time": null,
    "waitlist": null,
    "forms": [null],
    "documents": ["Proof of age (e.g., ID)", "Proof of income (e.g., tax returns, pay stubs)", "Proof of unemployment", "Veteran status if applicable (for priority)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Operated by grantees like SER Jobs For Progress (covers Kansas among other states) and potentially AARP Foundation; contact local provider (e.g., 316-771-6750 for Wichita area) as services may vary by host agencies and availability.[1][3][5]",
    "offices_or_providers": ["SER Jobs For Progress (Kansas WorkforceONE)", "Kansas SCSEP team (316-771-6750)", "Workforce Kansas providers"]
  },
  "official_source": "https://workforce-ks.com/programs/seniorcommunityserviceemploymentprogram/",
  "gotchas": ["Income limit strictly ≤125% FPL (not just 'low-income'); program is temporary training bridge to unsubsidized jobs, not permanent employment; priority tiers may cause delays for non-priority applicants; no asset test but poor employment prospects required; supportive services vary by grantee; must be unemployed to enroll.[2][5][7]"],
  "data_shape_notes": "Federally standardized (age 55+, ≤125% FPL, unemployed) but administered by grantees (e.g., SER in Kansas); benefits fixed at ~20 hours/week minimum wage; priority tiers affect access; no fixed income table or asset limits in sources—use annual federal poverty guidelines"
