{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident of a long-term care facility in Kansas (e.g., nursing homes, assisted living facilities, board and care homes, home plus facilities, adult day care centers, residential healthcare facilities). Services also extend to prospective residents, families, friends, community members, and facility staff with concerns about residents[1][4][5][7]."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Certified ombudsmen identify, investigate, and resolve complaints; provide information on long-term care services and resident rights; advocate for improvements in quality of life and care; represent residents before agencies for remedies; ensure access to services; handle issues from daily care to food service while protecting privacy and confidentiality. No fixed dollar amounts or hours; services are complaint-driven and person-centered[1][3][4][7].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-877-662-8362 or local (785) 296-3017[1][6]", "Email: LTCO@ks.gov[1]", "Website: https://www.ombudsman.ks.gov (find regional ombudsman or submit concerns)[6][8]", "In-person: Contact regional ombudsman offices (list available at https://www.ombudsman.ks.gov)[8]"],
    "processing_time": "Not specified; services provided as needed upon contact for complaint resolution.",
    "waitlist": null,
    "forms": ["No specific application form required for residents or families; contact directly to report concerns. Volunteer application exists but not for service recipients[1]."],
    "documents": ["No documents needed to request services; provide details of the concern or complaint verbally or via contact method[1][4]."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all Kansas long-term care facilities.",
    "regional_variations": "Program operates through regional ombudsman offices with local contacts, supervision, and training provided regionally, but core services are consistent statewide[1][8].",
    "offices_or_providers": ["State office: 900 SW Jackson Street, Suite 1041, Topeka, KS 66612[5]"; "Regional offices: Full list at https://www.ombudsman.ks.gov (\"Find Your Ombudsman\")[8]"]
  },
  "official_source": "https://www.ombudsman.ks.gov",
  "gotchas": ["Not a financial or direct service program (e.g., no payments, healthcare provision, or Medicaid application help—use KanCare Ombudsman for Medicaid issues)[4]"; "Open to anyone with concerns, not just residents or families—facility staff and community members can contact[4]"; "Focuses on advocacy and complaint resolution in certified long-term care settings only, not general elderly care outside facilities[1][4][7]"; "Confidentiality is paramount; resident determines involvement level[1]"],
  "data_shape_notes": "no income test; advocacy-only, complaint-driven services; delivered via regional volunteer and staff network statewide; distinct from KanCare Ombudsman for Medicaid"
}
